# =========================================================
# STREAMLIT COMPATIBILITY LAYER
# =========================================================
# The tfg_app environment may include an older Streamlit version. This block
# is intentionally idempotent so Streamlit reruns do not wrap st.button/st.image
# multiple times and cause recursion.
if not hasattr(st, "rerun") and hasattr(st, "experimental_rerun"):
    st.rerun = st.experimental_rerun

if not hasattr(st, "_tfg_original_image"):
    st._tfg_original_image = st.image

def _image_compat(*args, **kwargs):
    # Prefer the current Streamlit API to avoid deprecation warnings.
    # Fall back to the older parameter only when the installed version needs it.
    use_container = kwargs.pop("use_container_width", None)
    if use_container is not None and "width" not in kwargs and "use_column_width" not in kwargs:
        kwargs["width"] = "stretch" if use_container else "content"
    try:
        return st._tfg_original_image(*args, **kwargs)
    except TypeError as e:
        if "unexpected keyword argument 'width'" in str(e):
            width_value = kwargs.pop("width", None)
            if width_value == "stretch":
                kwargs["use_column_width"] = True
            return st._tfg_original_image(*args, **kwargs)
        raise

st.image = _image_compat

if not hasattr(st, "_tfg_original_button"):
    st._tfg_original_button = st.button

def _button_compat(*args, **kwargs):
    # Older Streamlit versions do not accept these button width parameters.
    kwargs.pop("use_container_width", None)
    kwargs.pop("use_column_width", None)
    try:
        return st._tfg_original_button(*args, **kwargs)
    except TypeError as e:
        # Some older versions may not support type="primary"/"secondary".
        if "unexpected keyword argument 'type'" in str(e):
            kwargs.pop("type", None)
            return st._tfg_original_button(*args, **kwargs)
        raise

st.button = _button_compat

if not hasattr(st, "_tfg_original_plotly_chart"):
    st._tfg_original_plotly_chart = st.plotly_chart

def _plotly_chart_compat(*args, **kwargs):
    try:
        return st._tfg_original_plotly_chart(*args, **kwargs)
    except TypeError as e:
        if "unexpected keyword argument 'use_container_width'" in str(e):
            kwargs.pop("use_container_width", None)
            return st._tfg_original_plotly_chart(*args, **kwargs)
        raise

st.plotly_chart = _plotly_chart_compat


