def embedded_png_bytes(b64_text: str):
    try:
        return base64.b64decode(b64_text)
    except Exception:
        return None

def local_image_src(path: str, fallback_b64: str = "") -> str:
    """Return a browser-compatible image src from a local path or fallback base64."""
    try:
        if path and os.path.exists(path):
            with open(path, "rb") as f:
                return "data:image/png;base64," + base64.b64encode(f.read()).decode("utf-8")
    except Exception:
        pass
    if fallback_b64:
        return "data:image/png;base64," + fallback_b64
    return ""

def image_to_base64(path: str) -> str:
    if not os.path.exists(path):
        return ""
    with open(path, "rb") as f:
        return base64.b64encode(f.read()).decode("utf-8")

def read_uploaded_image(uploaded_file) -> np.ndarray:
    image = Image.open(uploaded_file).convert("L")
    return np.array(image)

def percentile_normalize(img: np.ndarray, lower=1, upper=99) -> np.ndarray:
    img = img.astype(np.float32)
    p1, p99 = np.percentile(img, [lower, upper])
    if p99 - p1 < 1e-8:
        return np.zeros_like(img)
    img = np.clip(img, p1, p99)
    return (img - p1) / (p99 - p1)

def preprocess_for_segmentation(img_gray: np.ndarray) -> Tuple[np.ndarray, np.ndarray]:
    img_resized = cv2.resize(img_gray, SEG_INPUT_SIZE, interpolation=cv2.INTER_AREA)
    img_norm = percentile_normalize(img_resized)
    x_seg = np.stack([img_norm] * 3, axis=-1)
    return img_norm, np.expand_dims(x_seg, axis=0).astype(np.float32)

def extract_mask_components(bin_mask: np.ndarray):
    """Return connected-component descriptors without modifying the binary mask."""
    num_labels, labels, stats, _ = cv2.connectedComponentsWithStats(bin_mask.astype(np.uint8), connectivity=8)
    if num_labels <= 1:
        return None

    components = []
    for i in range(1, num_labels):
        components.append({
            "area": int(stats[i, cv2.CC_STAT_AREA]),
            "bbox": (
                int(stats[i, cv2.CC_STAT_LEFT]),
                int(stats[i, cv2.CC_STAT_TOP]),
                int(stats[i, cv2.CC_STAT_WIDTH]),
                int(stats[i, cv2.CC_STAT_HEIGHT]),
            ),
        })
    return components or None

def postprocess_mask(prob_mask, threshold, min_area, use_lcc):
    bin_mask = (prob_mask >= threshold).astype(np.uint8)
    num_labels, labels, stats, _ = cv2.connectedComponentsWithStats(bin_mask, connectivity=8)
    filtered = np.zeros_like(bin_mask)

    if num_labels <= 1:
        return filtered, None

    components = []
    kept = []
    for i in range(1, num_labels):
        area = int(stats[i, cv2.CC_STAT_AREA])
        if area >= min_area:
            kept.append((i, area))
            components.append({
                "area": area,
                "bbox": (
                    int(stats[i, cv2.CC_STAT_LEFT]),
                    int(stats[i, cv2.CC_STAT_TOP]),
                    int(stats[i, cv2.CC_STAT_WIDTH]),
                    int(stats[i, cv2.CC_STAT_HEIGHT]),
                ),
            })

    if not kept:
        return filtered, None

    if use_lcc:
        best_label = max(kept, key=lambda x: x[1])[0]
        filtered[labels == best_label] = 1
    else:
        for label_id, _ in kept:
            filtered[labels == label_id] = 1

    return filtered, components

def predict_segmentation_probability(seg_model, x_seg: np.ndarray) -> np.ndarray:
    """Predict segmentation probabilities, with optional TTA matching the final evaluation script."""
    p0 = seg_model.predict(x_seg, verbose=0)[0, ..., 0]

    if not SEG_USE_TTA:
        return p0

    x_lr = x_seg[:, :, ::-1, :]
    p_lr = seg_model.predict(x_lr, verbose=0)[0, :, ::-1, 0]

    x_ud = x_seg[:, ::-1, :, :]
    p_ud = seg_model.predict(x_ud, verbose=0)[0, ::-1, :, 0]

    x_lrud = x_seg[:, ::-1, ::-1, :]
    p_lrud = seg_model.predict(x_lrud, verbose=0)[0, ::-1, ::-1, 0]

    return ((p0 + p_lr + p_ud + p_lrud) / 4.0).astype(np.float32)

def make_overlay(gray_img_01, bin_mask, alpha=0.42):
    base = (gray_img_01 * 255).astype(np.uint8)
    rgb = cv2.cvtColor(base, cv2.COLOR_GRAY2RGB)
    overlay = rgb.copy()
    overlay[bin_mask == 1] = [255, 70, 70]
    return cv2.addWeighted(overlay, alpha, rgb, 1 - alpha, 0)

# =========================================================
# MODELS
# =========================================================
@st.cache_resource
def load_models():
    seg_model = tf.keras.models.load_model(
        SEG_MODEL_PATH, custom_objects=CUSTOM_OBJECTS_SEG, compile=False
    )
    with tf.keras.utils.custom_object_scope(CUSTOM_OBJECTS_CLS):
        full_cls_model = tf.keras.models.load_model(
            FULL_CLS_MODEL_PATH, custom_objects=CUSTOM_OBJECTS_CLS, compile=False
        )
    return seg_model, full_cls_model

# =========================================================
# INFERENCE
# =========================================================
def predict_scc_prob_from_gray_224(img_gray_224: np.ndarray, cls_model) -> float:
    img_norm = percentile_normalize(img_gray_224)
    x_cls = np.stack([(img_norm * 255.0)] * 3, axis=-1).astype(np.float32)
    return float(np.ravel(cls_model.predict(np.expand_dims(x_cls, 0), verbose=0))[0])

def run_segmentation(img_orig: np.ndarray) -> dict:
    seg_model, _ = load_models()
    img_256, x_seg = preprocess_for_segmentation(img_orig)
    seg_pred = predict_segmentation_probability(seg_model, x_seg)

    if SEG_INFERENCE_MODE.upper() == "RAW":
        bin_mask = (seg_pred >= SEG_THRESHOLD).astype(np.uint8)
        components = extract_mask_components(bin_mask)
    else:
        bin_mask, components = postprocess_mask(
            seg_pred,
            SEG_THRESHOLD,
            MIN_COMPONENT_AREA,
            USE_LARGEST_CC,
        )

    total_pixels = int(bin_mask.sum())
    overlay_img = make_overlay(img_256, bin_mask)
    mean_conf = float(seg_pred[bin_mask == 1].mean()) if np.any(bin_mask == 1) else 0.0
    return {
        "img_256": img_256,
        "seg_pred": seg_pred,
        "bin_mask": bin_mask,
        "overlay_img": overlay_img,
        "components": components,
        "total_pixels": total_pixels,
        "tumour_detected": total_pixels >= MIN_ACTIVE_PIXELS,
        "mean_mask_conf": mean_conf,
        "input_resolution": f"{img_orig.shape[1]}×{img_orig.shape[0]}",
        "seg_postproc_note": (
            f"threshold={SEG_THRESHOLD}, mode={SEG_INFERENCE_MODE}, TTA={SEG_USE_TTA}, "
            f"min_area={MIN_COMPONENT_AREA}, LCC={USE_LARGEST_CC}"
        ),
    }

def run_classification_direct(img_orig: np.ndarray) -> dict:
    _, full_cls_model = load_models()
    img_resized = cv2.resize(img_orig, CLS_INPUT_SIZE, interpolation=cv2.INTER_AREA)
    prob_scc = predict_scc_prob_from_gray_224(img_resized, full_cls_model)
    prob_adc = 1.0 - prob_scc
    pred_class = 1 if prob_scc >= FINAL_CLS_THRESHOLD else 0
    pred_label = POSITIVE_LABELS[pred_class]
    pred_conf = prob_scc if pred_class == 1 else prob_adc
    return {
        "roi": img_resized,
        "prob_scc": prob_scc,
        "prob_adc": prob_adc,
        "pred_class": pred_class,
        "pred_label": pred_label,
        "pred_conf": pred_conf,
        "input_resolution": f"{img_orig.shape[1]}×{img_orig.shape[0]}",
        "decision_source": "Full-image classifier",
        "threshold_used": FINAL_CLS_THRESHOLD,
    }

def run_classification_with_segmentation_gate(img_orig: np.ndarray) -> dict:
    """
    Runs segmentation first. Classification is only performed if a reliable
    tumour region is detected according to the segmentation active-pixel criterion.
    """
    seg_result = run_segmentation(img_orig)
    img_resized = cv2.resize(img_orig, CLS_INPUT_SIZE, interpolation=cv2.INTER_AREA)

    if not seg_result["tumour_detected"]:
        result = seg_result.copy()
        result.update({
            "roi": img_resized,
            "classification_performed": False,
            "prob_scc": None,
            "prob_adc": None,
            "pred_class": None,
            "pred_label": NEGATIVE_LABEL,
            "pred_conf": 0.0,
            "decision_source": "Segmentation gate",
            "threshold_used": FINAL_CLS_THRESHOLD,
            "classification_note": (
                f"No reliable tumour region was detected "
                f"({seg_result['total_pixels']} active pixels; minimum required: {MIN_ACTIVE_PIXELS}). "
                "Subtype classification was not performed."
            ),
        })
        return result

    cls_result = run_classification_direct(img_orig)
    cls_result.update({
        "classification_performed": True,
        "tumour_detected": True,
        "total_pixels": seg_result["total_pixels"],
        "mean_mask_conf": seg_result["mean_mask_conf"],
        "img_256": seg_result["img_256"],
        "bin_mask": seg_result["bin_mask"],
        "overlay_img": seg_result["overlay_img"],
        "components": seg_result["components"],
        "seg_postproc_note": seg_result["seg_postproc_note"],
        "classification_note": (
            "A reliable tumour region was detected by the segmentation gate. "
            "Subtype classification was performed on the full image."
        ),
    })
    return cls_result

def run_pipeline_final(img_orig: np.ndarray) -> dict:
    seg_result = run_segmentation(img_orig)

    if not seg_result["tumour_detected"]:
        result = seg_result.copy()
        result.update({
            "classification_performed": False,
            "prob_scc_full": None,
            "prob_adc_full": None,
            "prob_scc_final": None,
            "prob_adc_final": None,
            "pred_class": None,
            "pred_label": NEGATIVE_LABEL,
            "pred_conf": 0.0,
            "decision_source": "Segmentation gate",
            "threshold_used": FINAL_CLS_THRESHOLD,
            "pipeline_note": (
                f"No reliable tumour region was detected "
                f"({seg_result['total_pixels']} active pixels; minimum required: {MIN_ACTIVE_PIXELS}). "
                "Subtype classification was not performed."
            ),
        })
        return result

    cls_result = run_classification_direct(img_orig)

    result = seg_result.copy()
    result.update({
        "classification_performed": True,
        "prob_scc_full": cls_result["prob_scc"],
        "prob_adc_full": cls_result["prob_adc"],
        "prob_scc_final": cls_result["prob_scc"],
        "prob_adc_final": cls_result["prob_adc"],
        "pred_class": cls_result["pred_class"],
        "pred_label": cls_result["pred_label"],
        "pred_conf": cls_result["pred_conf"],
        "decision_source": "Full-image classifier after segmentation gate",
        "threshold_used": FINAL_CLS_THRESHOLD,
        "pipeline_note": "A reliable tumour region was detected. Final subtype decision uses the full-image classifier.",
    })
    return result
