def build_probability_bar(prob_adc: float, prob_scc: float, title: str = "Subtype probabilities"):
    fig = go.Figure()
    fig.add_trace(go.Bar(
        y=["Adenocarcinoma (ADC)", "Squamous Cell Carcinoma (SCC)"],
        x=[prob_adc, prob_scc],
        orientation="h",
        text=[f"{prob_adc*100:.1f}%", f"{prob_scc*100:.1f}%"],
        textposition="outside",
        marker=dict(color=["#5f8fca", "#1f5db7"]),
        hovertemplate="%{y}: %{x:.3f}<extra></extra>",
    ))
    fig.update_layout(
        title=title,
        height=270,
        margin=dict(l=24, r=24, t=52, b=20),
        xaxis=dict(range=[0, 1], title="Probability"),
        yaxis=dict(title="", automargin=True),
        plot_bgcolor="rgba(0,0,0,0)",
        paper_bgcolor="rgba(0,0,0,0)",
        font=dict(color="#18324d"),
        bargap=0.45,
    )
    return fig

def build_seg_metrics_chart():
    labels = ["Dice"]
    values = [float(GLOBAL_SEG_DICE)]
    colors = ["#2f6fa5"]
    return _bar_chart(labels, values, colors, "Segmentation model performance")

def build_cls_metrics_chart():
    labels = ["Accuracy", "Balanced Acc.", "AUC"]
    values = [float(GLOBAL_CLS_ACC), float(GLOBAL_BAL_ACC), float(GLOBAL_AUC)]
    colors = ["#4d89b8", "#6b9ec5", "#91b6d6"]
    return _bar_chart(labels, values, colors, "Final classification performance")

def build_global_metrics_chart():
    labels = ["Dice", "Accuracy", "Balanced Acc.", "AUC"]
    values = [float(GLOBAL_SEG_DICE), float(GLOBAL_CLS_ACC), float(GLOBAL_BAL_ACC), float(GLOBAL_AUC)]
    colors = ["#2f6fa5", "#4d89b8", "#6b9ec5", "#91b6d6"]
    return _bar_chart(labels, values, colors, "Model performance overview")

def _bar_chart(labels, values, colors, title):
    fig = go.Figure(data=[go.Bar(
        x=labels,
        y=values,
        marker=dict(color=colors),
        text=[f"{v:.3f}" for v in values],
        textposition="outside",
        hovertemplate="%{x}: %{y:.3f}<extra></extra>",
    )])
    fig.update_layout(
        title=title,
        height=315,
        margin=dict(l=20, r=20, t=52, b=20),
        yaxis=dict(range=[0, 1.08]),
        xaxis=dict(title=""),
        plot_bgcolor="rgba(0,0,0,0)",
        paper_bgcolor="rgba(0,0,0,0)",
        font=dict(color="#18324d"),
    )
    return fig

