def component_count(components) -> int:
    return 0 if not components else len(components)

def largest_component_bbox_text(components) -> str:
    if not components:
        return "—"
    best = max(components, key=lambda x: x.get("area", 0))
    x, y, w, h = best["bbox"]
    return f"x={x}, y={y}, w={w}, h={h}"


def segmentation_shape_metrics(result: dict) -> dict:
    """Compute case-level descriptors from the final binary segmentation mask."""
    mask = np.asarray(result.get("bin_mask", []), dtype=np.uint8)
    img = np.asarray(result.get("img_256", []))
    if mask.size == 0 or mask.ndim != 2:
        return {
            "area": 0,
            "area_ratio": 0.0,
            "perimeter": 0.0,
            "compactness": 0.0,
            "centroid": "—",
            "mean_intensity": 0.0,
        }

    area = int(mask.sum())
    h, w = mask.shape[:2]
    area_ratio = (area / float(h * w) * 100.0) if h and w else 0.0

    if area > 0:
        contours, _ = cv2.findContours((mask * 255).astype(np.uint8), cv2.RETR_EXTERNAL, cv2.CHAIN_APPROX_SIMPLE)
        perimeter = float(sum(cv2.arcLength(cnt, True) for cnt in contours)) if contours else 0.0
        compactness = float((4.0 * np.pi * area) / (perimeter ** 2)) if perimeter > 0 else 0.0
        ys, xs = np.where(mask > 0)
        centroid = f"({ys.mean():.1f}, {xs.mean():.1f})" if len(ys) else "—"
        mean_intensity = float(img[mask > 0].mean()) if img.size and img.shape[:2] == mask.shape else 0.0
    else:
        perimeter = 0.0
        compactness = 0.0
        centroid = "—"
        mean_intensity = 0.0

    return {
        "area": area,
        "area_ratio": area_ratio,
        "perimeter": perimeter,
        "compactness": compactness,
        "centroid": centroid,
        "mean_intensity": mean_intensity,
    }


