        ("Perimeter", f"{metrics['perimeter']:.0f} px", "Approximate length of the tumour boundary."),
        ("Compactness (4πA/P²)", f"{metrics['compactness']:.3f}", "Shape descriptor; lower values suggest more irregular boundaries."),
        ("Centroid (row, col)", metrics["centroid"], "Approximate centre of the predicted tumour region in image coordinates."),
        ("Mean intensity (a.u.)", f"{metrics['mean_intensity']:.1f}", "Average image intensity within the segmented tumour region."),
