def render_access_mode_buttons():
    """Pill-style access selector compatible with older Streamlit versions."""
    if "access_option" not in st.session_state or st.session_state.access_option not in [
        "Log in", "Create account", "Continue as visitor"
    ]:
        st.session_state.access_option = "Log in"

    st.markdown('<div class="access-mode-label">Select access mode</div>', unsafe_allow_html=True)
    c1, c2, c3 = st.columns(3, gap="small")

    with c1:
        if st.button(
            "👤  Log in",
            key="access_mode_login_btn",
            type="primary" if st.session_state.access_option == "Log in" else "secondary",
            use_container_width=True,
        ):
            st.session_state.access_option = "Log in"
            st.rerun()

    with c2:
        if st.button(
            "👥  Create account",
            key="access_mode_create_btn",
            type="primary" if st.session_state.access_option == "Create account" else "secondary",
            use_container_width=True,
        ):
            st.session_state.access_option = "Create account"
            st.rerun()

    with c3:
        if st.button(
            "👁  Visitor access",
            key="access_mode_visitor_btn",
            type="primary" if st.session_state.access_option == "Continue as visitor" else "secondary",
            use_container_width=True,
        ):
            st.session_state.access_option = "Continue as visitor"
            st.rerun()



