    st.markdown('<div class="login-only-single-card-anchor"></div>', unsafe_allow_html=True)
    left_col, right_col = st.columns([0.84, 1.16], gap="large")

    with left_col:
        st.markdown(
            f'''<div class="login-title">{APP_TITLE}</div>
            <div class="login-subtitle">
                Access the academic demonstrator for lung tumour segmentation,
                subtype classification, and complete pipeline visualisation.
                Images are processed in memory and are not stored.
            </div>
            <div class="login-privacy-box">
                <div class="privacy-head">
                    <div class="privacy-icon">🛡</div>
                    <div>Privacy and data handling</div>
                </div>
                <div class="privacy-row"><span class="privacy-check">✓</span><span>Access events are recorded for traceability.</span></div>
                <div class="privacy-row"><span class="privacy-check">✓</span><span>Uploaded images are not stored.</span></div>
                <div class="privacy-row"><span class="privacy-check">✓</span><span>Local accounts store only username and salted password hash.</span></div>
                <div class="privacy-row"><span class="privacy-check">✓</span><span>Case metrics are saved only when explicitly enabled.</span></div>
            </div>''',
            unsafe_allow_html=True,
        )

    with right_col:
        st.markdown('<div class="access-card-anchor"></div>', unsafe_allow_html=True)
        st.markdown(
            f'''<div class="login-static-banner"><div class="login-static-banner-fill" style="background-image: url('{login_banner_src}');"></div></div>
            <div class="access-card-title">Access portal</div>
            <div class="access-card-desc">Choose how you want to access the academic demo.</div>''',
            unsafe_allow_html=True,
        )

        render_access_mode_buttons()
        access_option = st.session_state.access_option

        if access_option == "Log in":
            st.markdown(
                '''<div class="access-section-title">Log in</div>
                <div class="access-section-desc">Use an existing local account or one of the predefined demo accounts.</div>''',
                unsafe_allow_html=True,
            )
            username = st.text_input("Username", key="login_username")
            password = st.text_input("Password", type="password", key="login_password")

            if st.button("🔒  Sign in", key="btn_login", type="primary", use_container_width=True):
                username_clean = normalise_username(username)
                if authenticate_user(username_clean, password):
                    start_authenticated_session(username_clean, "registered_existing_user")
                    st.rerun()
                else:
                    st.error("Incorrect username or password.")
                    
        elif access_option == "Create account":
            st.markdown(
                '''<div class="access-section-title">Create account</div>
                <div class="access-section-desc">Create a local account for this academic demo. Passwords are stored as salted hashes, not as plain text.</div>''',
                unsafe_allow_html=True,
            )
            new_username = st.text_input("Choose username", key="register_username")
            new_password = st.text_input("Choose password", type="password", key="register_password")
            confirm_password = st.text_input("Confirm password", type="password", key="register_confirm_password")

            if st.button("＋  Create account and enter", key="btn_create_account", type="primary", use_container_width=True):
                is_valid, username_clean, message = validate_new_account(new_username, new_password, confirm_password)
                if not is_valid:
                    st.error(message)
                else:
                    create_local_user_account(username_clean, new_password)
                    start_authenticated_session(username_clean, "registered_new_user")
                    st.success("Account created successfully.")
                    st.rerun()

        else:
            st.markdown(
                '''<div class="access-section-title">Visitor access</div>
                <div class="access-section-desc">Continue without creating an account and without entering credentials. The session is recorded as visitor access.</div>''',
                unsafe_allow_html=True,
            )
            if st.button("👁  Enter as visitor", key="btn_visitor", type="primary", use_container_width=True):
                visitor_name = f"visitor_{uuid.uuid4().hex[:6]}"
                start_authenticated_session(visitor_name, "visitor")
                st.rerun()
    footer()

